game_info.concept:
{
  "game_name": "Brain Test: Tricky Puzzles",
  "genre": "Family",
  "core_mechanics": {
    "player_actions": {
      "tap": "Corresponds to a mouse click (mouseReleased) on an interactive element or specific screen area.",
      "drag": "Corresponds to a mouse press (mousePressed) followed by mouse movement (mouseDragged), releasing with mouseReleased. This allows repositioning or manipulating an object.",
      "swipe": "Similar to drag, but the direction and speed of the mouse movement between mousePressed and mouseReleased determines the 'swipe' action (e.g., swiping left, right, up, down) on an object or the entire screen."
    },
    "game_rules_systems": [
      "Each puzzle is a self-contained scenario with a single, unique solution.",
      "Solutions require 'thinking outside the box' and experimenting with unconventional interactions.",
      "No timers or pressure; players can take unlimited time to solve a puzzle.",
      "Progression is strictly linear; completing a puzzle immediately advances the player to the next puzzle in sequence.",
      "Hints are available via a dedicated button/key, which incurs a score penalty.",
      "Specific game state (e.g., position, visibility, rotation) of interactive elements dictates puzzle resolution."
    ],
    "tracked_state": [
      "currentPuzzleId: Integer representing the current puzzle being played.",
      "interactiveElementsState: Array/Object storing the current properties (x, y, rotation, scale, visibility, status) of all interactive objects for the current puzzle.",
      "hintUsedCount: Integer tracking how many hints have been used for the current puzzle.",
      "playerScore: Integer tracking the cumulative score across all levels.",
      "currentLevel: Integer indicating the player's current level.",
      "puzzleSolved: Boolean flag indicating if the current puzzle's solution condition has been met."
    ]
  },
  "visual_elements": {
    "game_objects": [
      {
        "name": "Puzzle Background",
        "representation": "Static images or p5.js drawing primitives (rect, circle, line) forming the base scenario for each puzzle."
      },
      {
        "name": "Interactive Elements",
        "representation": "P5.js shapes (rectangles, circles, custom polygons) or loaded images. They will have a subtle visual indicator (e.g., faint glow, outline, slightly different fill) when selected via keyboard or hovered over by mouse. Specific states like being dragged will have temporary visual feedback (e.g., slight scale change, pulsating outline)."
      },
      {
        "name": "Non-Interactive Decor",
        "representation": "Static p5.js shapes or background images that are part of the puzzle's visual context but don't respond to direct player input."
      },
      {
        "name": "UI Elements",
        "representation": "Text for instructions, scores, level indicators (e.g., 'Level 1', 'Score: 1234'). Buttons for 'Hint', 'Next Puzzle' (after solved), 'Pause', 'Main Menu'. These will be simple rectangles with text labels, possibly iconic. A 'Solved!' overlay will appear upon puzzle completion."
      }
    ],
    "animations_effects": [
      "Interaction Feedback: Interactive elements will briefly change color, scale, or flash upon successful tap/drag/swipe detection.",
      "Solution Confirmation: A short 'success' animation (e.g., sparkling particles, a checkmark icon, brief screen flash) will play when a puzzle is solved.",
      "Hint Display: An overlay with textual hint will appear, possibly with an arrow pointing to a relevant area or object.",
      "Level Transition: Fade-out to black, followed by a 'Level Complete!' message, then fade-in to the next level's puzzle.",
      "Keyboard Selection Highlight: A distinct border or glow around the currently selected interactive element."
    ]
  },
  "control_scheme": {
    "ArrowLeft": "Select the previous interactive object on screen (cycles through available objects). If an object is selected and Shift is held, 'drag/swipe' the selected object left.",
    "ArrowRight": "Select the next interactive object on screen (cycles through available objects). If an object is selected and Shift is held, 'drag/swipe' the selected object right.",
    "ArrowUp": "If an object is selected and Shift is held, 'drag/swipe' the selected object up.",
    "ArrowDown": "If an object is selected and Shift is held, 'drag/swipe' the selected object down.",
    "Space": "Perform a 'tap' action on the currently selected interactive object. This triggers its primary interaction.",
    "Shift": "Modifier key. When held down in combination with Arrow keys, it transforms the arrow key press into a 'drag/swipe' action on the currently selected object. Without Shift, arrow keys cycle selection.",
    "Z": "Toggle Hint display. Press once to show hint, press again to hide.",
    "W": "No assigned function for general game mechanics; reserved for puzzle-specific unique interactions if required.",
    "A": "No assigned function for general game mechanics; reserved for puzzle-specific unique interactions if required.",
    "S": "No assigned function for general game mechanics; reserved for puzzle-specific unique interactions if required.",
    "D": "No assigned function for general game mechanics; reserved for puzzle-specific unique interactions if required.",
    "special_key_combinations": [
      "Shift + ArrowLeft: Drag/swipe the currently selected object left.",
      "Shift + ArrowRight: Drag/swipe the currently selected object right.",
      "Shift + ArrowUp: Drag/swipe the currently selected object up.",
      "Shift + ArrowDown: Drag/swipe the currently selected object down."
    ]
  },
  "game_states": {
    "states": [
      "MAIN_MENU: Player is on the main screen, can start game, view high scores, etc.",
      "PLAYING_PUZZLE: Player is actively attempting to solve a puzzle, interacting with elements.",
      "PUZZLE_SOLVED_TRANSITION: Brief state after solving a puzzle, showing 'Puzzle Solved!' message and score update, before loading the next puzzle.",
      "HINT_ACTIVE: A hint is displayed over the puzzle. Player can still interact with the puzzle.",
      "PAUSED: Game is paused, with a pause menu overlay. Puzzle interaction is frozen.",
      "GAME_COMPLETE: All levels and puzzles have been successfully completed. Displays final score and high score entry."
    ],
    "transitions": [
      {
        "from": "MAIN_MENU",
        "to": "PLAYING_PUZZLE",
        "trigger": "Player clicks 'Start Game' button."
      },
      {
        "from": "PLAYING_PUZZLE",
        "to": "PUZZLE_SOLVED_TRANSITION",
        "trigger": "Correct puzzle interaction detected, satisfying the puzzle's win condition."
      },
      {
        "from": "PUZZLE_SOLVED_TRANSITION",
        "to": "PLAYING_PUZZLE",
        "trigger": "After a short delay (e.g., 2 seconds), load the next puzzle. If all puzzles are done, transition to GAME_COMPLETE."
      },
      {
        "from": "PLAYING_PUZZLE",
        "to": "HINT_ACTIVE",
        "trigger": "Player presses 'Z' (Hint key)."
      },
      {
        "from": "HINT_ACTIVE",
        "to": "PLAYING_PUZZLE",
        "trigger": "Player presses 'Z' again or clicks 'Close Hint' button."
      },
      {
        "from": "PLAYING_PUZZLE",
        "to": "PAUSED",
        "trigger": "Player presses 'P' or 'Esc' key."
      },
      {
        "from": "PAUSED",
        "to": "PLAYING_PUZZLE",
        "trigger": "Player presses 'P' or 'Esc' key again, or selects 'Resume' from pause menu."
      },
      {
        "from": "PUZZLE_SOLVED_TRANSITION",
        "to": "GAME_COMPLETE",
        "trigger": "The last puzzle of the final level has been solved."
      }
    ]
  },
  "win_conditions": "The player wins by successfully solving the specific interaction or sequence of interactions that resolves the current puzzle scenario. The game is fully 'won' when all puzzles across all defined levels have been completed.",
  "lose_conditions": "There are no traditional 'lose' conditions (e.g., health depletion, time running out) in Brain Test: Tricky Puzzles. The game is designed for a relaxed experience. Players cannot fail permanently or get a 'Game Over' for incorrect actions. The only 'failure' is the inability to solve a puzzle without resorting to hints, which incurs a score penalty but doesn't stop progression.",
  "scoring_system": {
    "point_actions": [
      "+100 points for successfully completing any puzzle.",
      "+50 bonus points for completing a puzzle without using any hints.",
      "-25 points for each hint used on a puzzle.",
      "+25 bonus points for completing a puzzle with a 'minimal interaction' score (e.g., 1-3 taps/drags, specific to each puzzle's design)."
    ],
    "bonus_multipliers": "No explicit multipliers for this game's design, but the 'no hint' and 'minimal interaction' bonuses serve a similar purpose.",
    "high_score_system": "Yes, a local high score system will track the highest total score achieved across a full playthrough of all levels. This high score will be displayed on the Main Menu and Game Complete screens.",
    "display_format": "The current player's score will be displayed prominently in the top-right corner of the screen during PLAYING_PUZZLE state. Format: 'Score: [currentScoreValue]'. Font: sans-serif, size 24px, color white, right-aligned.",
    "score_effect_on_gameplay": "The score primarily serves as a metric for player performance and bragging rights via the high score system. It does not directly affect puzzle mechanics or progression (e.g., no 'lamps' currency linked to score)."
  },
  "level_system": {
    "total_levels": 3,
    "progression_logic": "Player advances to the next level upon successfully completing all puzzles within the current level. A 'LEVEL COMPLETE!' screen is displayed during transition.",
    "level_indicator_display": "A text display 'Level [currentLevelNumber]' will be shown in the top-left corner of the screen during gameplay.",
    "level_details": [
      {
        "level_number": 1,
        "name": "Introduction to Mechanics",
        "puzzles_count": "3-5 puzzles",
        "difficulty_increase": "Simplest interactions, often involving a single interactive object and straightforward misdirection. Focus on basic tap and drag mechanics. Interactive elements are clearly discernible.",
        "example_puzzle_type": "Tap the correct shape out of several similar ones. Drag an object to reveal another behind it. Swipe an item off-screen to solve."
      },
      {
        "level_number": 2,
        "name": "Combining Interactions & Subtle Misdirection",
        "puzzles_count": "5-7 puzzles",
        "difficulty_increase": "Puzzles require sequential actions or combining interactions between two or more objects. Misdirection becomes more subtle, requiring closer observation. Introduction of physics-based interactions using Matter.js (e.g., stacking, knocking over).",
        "example_puzzle_type": "Drag object A onto object B, then tap C. Swipe down to make an item fall, then drag it. Use a physical interaction to create an opening."
      },
      {
        "level_number": 3,
        "name": "Advanced Logic & Environmental Interaction",
        "puzzles_count": "7-10 puzzles",
        "difficulty_increase": "Solutions involve more abstract thinking, manipulating the environment itself (e.g., dragging the background, using screen boundaries), or interacting with elements that initially appear non-interactive. Physics might be used for less obvious solutions (e.g., balancing).",
        "example_puzzle_type": "Drag the entire screen to reveal an off-screen element. Discover a hidden interactive area by 'shaking' the screen (via repeated left/right swipes). Use an object's properties (e.g., transparency) to solve."
      }
    ]
  },
  "simplifications": [
    "**Hint System:** The original 'lamps currency' system for hints is simplified to a direct score penalty per hint used, removing any currency management or in-game economy.",
    "**Puzzle Quantity:** The original 'hundreds of puzzles' is significantly reduced to a manageable set (e.g., 15-20 total across 3 levels) for an HTML5 implementation.",
    "**Graphics Fidelity:** Complex high-resolution assets are simplified to p5.js drawing primitives and basic images for ease of development and performance in a browser environment.",
    "**Keyboard Control Abstraction:** Adapting free-form touch/drag/swipe interactions to a specific set of keyboard controls requires an abstraction layer (e.g., object selection via arrow keys) that differs significantly from direct touch input. This simplifies the input method for desktop but might make some original puzzle types less intuitive without a direct mouse click/drag.",
    "**Matter.js Integration:** Matter.js will be used selectively for puzzles where physics interactions are central to the solution. Many puzzles will rely purely on p5.js drawing and custom hit-detection logic, avoiding overly complex physics simulations for every scenario."
  ],
  "implementation_notes": {
    "score_display_p5js": "The score will be rendered using `text('Score: ' + playerScore, width - 150, 30);` in p5.js, positioned in the top-right corner. The `textStyle(BOLD); textSize(24); fill(255); textAlign(RIGHT);` will be used for clarity.",
    "level_progression_logic": "Each puzzle will have a `checkWinCondition()` function. Upon `true` return, `currentPuzzleIndex` increments. If `currentPuzzleIndex` exceeds `puzzlesInCurrentLevel`, `currentLevel` increments, and a new set of puzzles for that level is loaded. A `puzzleData` array of objects (one per puzzle) will store win conditions, hints, and interactive element initial states.",
    "matter_js_usage": "Matter.js will be initialized as a `Matter.Engine` instance. For puzzles requiring physics, `Matter.Bodies` will be created corresponding to p5.js visual elements. Collision detection and physical interactions will be handled by Matter.js, then synchronized with p5.js rendering. For puzzles not requiring physics, Matter.js will be bypassed or minimally used.",
    "keyboard_control_adaptation": "For keyboard controls, a `selectedInteractiveObject` variable will be maintained. Arrow keys will cycle through an array of `interactiveObjects` for the current puzzle, visually highlighting the currently selected one. `Space` will trigger its `onTap()` method, and `Shift + Arrow` will call `onDrag(direction)` on the selected object. Mouse interactions (click, drag) will take precedence if present, directly affecting the clicked/dragged object. This selection system is crucial for keyboard usability and will require careful implementation for each puzzle's interactive elements."
  }
}
